',{id:"xref_environmental_justice_score_vs_income",title:"EPA EJScreen environmental justice score vs. median income by census tract - pollution as a poverty tax",sub:"The 5% of census tracts with the highest EJScreen cumulative environmental burden scores average median household income of $28,400. The 5% with lowest burden: $92,100. The correlation (-0.71) confirms that environmental hazards are not distributed randomly - they follow the income gradient with near-perfect fidelity.",type:"XREF",geo:"us_county",fmt:"County choropleth",tbl:"EPA EJScreen environmental justice scores + ACS tract income (both public)",section:"Geography",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by county (bls.gov - free)"],vars:["median_household_income","rural_population_pct"],join:["pct_on_snap","pct_bachelors","per_capita_health_spending"],sc:{emotional:8,relatability:6,surprise:7,tension:7,visual:5,data_ready:9,originality:5},vs:72,tags:"EJScreen environmental justice income census tract 5% highest $28400 lowest $92100 r=-0.71 hazards not random income gradient EPA EJScreen ACS tract pollution poverty tax"}',
',{id:"global_renewable_energy_share_trend_2000_2025",title:"Renewable energy share of electricity by country 2000-2025 - the great energy transition in progress",sub:"Iceland: 100% renewable electricity (geothermal + hydro) for 50 years. Norway: 98%. Denmark: 88% in 2024 vs. 17% in 2000. Germany: 62% vs. 6% in 2000. USA: 21% vs. 8% in 2000. The transition acceleration is real and global but the starting points and rates vary enormously.",type:"MAP",geo:"worldwide",fmt:"World choropleth",tbl:"IEA Electricity Market Report 2025 + Ember Global Electricity Review (both public)",section:"Energy",ext:["World Bank Open Data: GDP, population, income by country (data.worldbank.org - free API)"],vars:["renewable_energy_share","energy_consumption_per_capita"],join:["rd_pct_gdp","trade_balance_goods","net_migration_rate"],sc:{emotional:7,relatability:6,surprise:7,tension:5,visual:8,data_ready:8,originality:4},vs:63,tags:"renewable energy share electricity country 2000 2025 Iceland 100% Norway 98% Denmark 88% 17% Germany 62% 6% USA 21% 8% transition acceleration IEA Electricity Ember Global Review"}',
',{id:"xref_heat_pump_adoption_vs_heating_costs",title:"Heat pump adoption rate vs. home heating cost savings by state - the electrification math",sub:"Massachusetts: heat pump adoption 8.4% of new HVAC installs in 2024, average household heating cost savings $1,200/year vs. natural gas. Maine: 14.1% adoption (highest in New England). The economics favor heat pumps in almost all US climates but adoption requires upfront cost that low-income households cannot access.",type:"XREF",geo:"us_state",fmt:"Scatter plot",tbl:"EIA residential energy survey + NEEP heat pump data (both public)",section:"Energy",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","EIA State Energy Data System: production + consumption by state (eia.gov - free API)"],vars:["renewable_energy_share","energy_consumption_per_capita"],join:["median_household_income","housing_cpi","pct_bachelors"],sc:{emotional:6,relatability:7,surprise:7,tension:4,visual:4,data_ready:7,originality:6},vs:57,tags:"heat pump adoption heating cost savings state Massachusetts 8.4% $1200 Maine 14.1% highest New England economics favor upfront low-income cannot EIA residential NEEP heat pump electrification"}',
',{id:"xref_gas_stove_indoor_air_vs_childhood_asthma",title:"Gas stove prevalence vs. childhood asthma rate by state - the kitchen air quality link",sub:"States with 60%+ gas stove prevalence have childhood asthma rates 19% higher than states under 20% prevalence, after controlling for urbanization and income. Stanford study: gas stoves responsible for 12.7% of US childhood asthma cases. The kitchen as an air quality hazard is newly documented.",type:"XREF",geo:"us_state",fmt:"Scatter plot",tbl:"EIA residential energy survey gas stove prevalence + CDC BRFSS childhood asthma (both public)",section:"Health",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","CDC WONDER: mortality + disease rates by county/state (wonder.cdc.gov - free)"],vars:["per_capita_health_spending","rural_population_pct"],join:["median_household_income","pct_on_medicaid","uninsured_rate"],sc:{emotional:8,relatability:8,surprise:8,tension:6,visual:4,data_ready:7,originality:7},vs:72,tags:"gas stove indoor air childhood asthma state 60%+ 19% higher 20% urbanization income Stanford 12.7% childhood asthma kitchen air quality hazard EIA residential CDC BRFSS"}',
',{id:"xref_electric_grid_reliability_vs_extreme_weather",title:"Grid reliability hours vs. extreme weather events by state 2015-2024 - infrastructure vs. climate",sub:"Texas: 18.6 hours of power outages per customer in 2021 (Winter Storm Uri alone). Louisiana: 11.2 hours per customer in 2021 (Ida). National average: 8.0 hours per customer per year. Grid reliability is inversely correlated with extreme weather frequency (r=-0.61) but the relationship is moderated by grid investment.",type:"XREF",geo:"us_state",fmt:"Scatter plot",tbl:"EIA Form 861 utility reliability data + NOAA billion-dollar disaster database (both public)",section:"Energy",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","EIA State Energy Data System: production + consumption by state (eia.gov - free API)"],vars:["renewable_energy_share","energy_consumption_per_capita"],join:["median_household_income","rep_pct","housing_permits_total"],sc:{emotional:7,relatability:7,surprise:7,tension:7,visual:5,data_ready:7,originality:6},vs:65,tags:"grid reliability extreme weather state Texas 18.6 hours Uri Louisiana 11.2 Ida national 8.0 r=-0.61 investment moderated EIA Form 861 NOAA billion-dollar disaster infrastructure climate"}',
',{id:"xref_corporate_sustainability_pledge_vs_emissions",title:"Corporate sustainability pledge date vs. actual emissions trajectory - the gap between promise and action",sub:"Fortune 500 companies with net-zero pledges made before 2020 show average Scope 1+2 emissions reduction of 18% by 2024. Companies pledging after 2020: 4% reduction. The pledge-action gap is widening. Of 100 companies with 2030 emission targets, 87% are not on track to meet them.",type:"CHART",geo:"us_national",fmt:"Scatter plot",tbl:"CDP Scope 1+2 emissions data + SBTi target tracking 2024 (public)",section:"Energy",ext:["FRED: any national economic time series (fred.stlouisfed.org - free API)","World Bank Open Data: GDP, population, income by country (data.worldbank.org - free API)"],vars:["renewable_energy_share","rd_pct_gdp"],join:["trade_balance_goods","net_migration_rate","population_pct_change_2020_2025"],sc:{emotional:7,relatability:6,surprise:8,tension:7,visual:5,data_ready:6,originality:7},vs:64,tags:"corporate sustainability pledge emissions trajectory before 2020 18% after 2020 4% gap widening 100 companies 2030 targets 87% not on track CDP SBTi tracking promise action Fortune 500"}',
',{id:"us_superfund_site_vs_cancer_cluster_county",title:"Superfund site locations vs. cancer incidence rate by county - mapping toxic legacies",sub:"Counties with active Superfund sites have cancer incidence rates 7.2% higher than comparable counties without sites, after controlling for income, smoking, and age. The legacy of 20th-century industrial pollution is geographically concentrated and medically measurable 30+ years later.",type:"XREF",geo:"us_county",fmt:"County choropleth",tbl:"EPA Superfund NPL + NCI SEER cancer incidence by county (both public)",section:"Health",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by county (bls.gov - free)","CDC WONDER: mortality + disease rates by county/state (wonder.cdc.gov - free)"],vars:["median_household_income","rural_population_pct"],join:["pct_on_snap","per_capita_health_spending","pct_bachelors"],sc:{emotional:8,relatability:6,surprise:7,tension:7,visual:7,data_ready:8,originality:6},vs:71,tags:"Superfund site cancer incidence county 7.2% higher controlled income smoking age industrial pollution 30+ years geographically concentrated measurable EPA NPL NCI SEER toxic legacies"}',
',{id:"xref_oil_gas_royalty_vs_state_public_services",title:"Oil and gas royalty revenue vs. public service quality by state - the resource curse at home?",sub:"Wyoming receives $1.4B in annual mineral royalties - 55% of state revenue. Alaska: 85% of state budget from oil. But both states rank in the bottom 20 for education and healthcare outcomes. The domestic resource curse: states dependent on extraction revenue show worse social outcomes than diversified-economy states.",type:"XREF",geo:"us_state",fmt:"Scatter plot",tbl:"ONRR royalty revenue by state + US News state rankings public services (public)",section:"Energy",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","EIA State Energy Data System: production + consumption by state (eia.gov - free API)"],vars:["oil_gas_extraction_index","renewable_energy_share"],join:["state_local_revenue_per_capita","expenditure_per_pupil","per_capita_health_spending"],sc:{emotional:7,relatability:5,surprise:7,tension:5,visual:5,data_ready:6,originality:7},vs:59,tags:"oil gas royalty public services state Wyoming $1.4B 55% Alaska 85% bottom 20 education healthcare domestic resource curse extraction diversified outcomes ONRR US News rankings"}',
',{id:"xref_climate_belief_vs_flood_insurance_purchase",title:"Climate change belief vs. flood insurance purchase rate by county - knowing vs. acting on risk",sub:"Counties where 70%+ of residents believe climate change is real and human-caused show NFIP participation rates of 31% in flood zones. Counties where under 40% believe: 28% NFIP participation. The gap is nearly zero. Believing in climate risk is not predictive of purchasing insurance against it - action costs money, belief is free.",type:"XREF",geo:"us_county",fmt:"Scatter plot",tbl:"Yale Climate Opinion Maps + FEMA NFIP enrollment by county (both public)",section:"Geography",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by county (bls.gov - free)"],vars:["coastline_miles","flood_zone_uninsured_pct"],join:["median_household_income","rep_pct","housing_permits_total"],sc:{emotional:7,relatability:7,surprise:9,tension:5,visual:4,data_ready:7,originality:9},vs:73,tags:"climate belief flood insurance purchase county 70%+ 31% NFIP under 40% 28% gap near zero believing not predictive action costs money belief free Yale Climate Opinion FEMA NFIP"}',
